impl Basic {
    #[doc = r" Returns the hex color value (including the # prefix)"]
    pub fn hex(&self) -> &'static str {
        match self {
            Basic::Black => "#000000",
            Basic::Blue => "#0000ff",
            Basic::Cyan => "#00ffff",
            Basic::Green => "#008000",
            Basic::Teal => "#008080",
            Basic::Turquoise => "#40e0d0",
            Basic::Indigo => "#4b0082",
            Basic::Gray => "#808080",
            Basic::Purple => "#800080",
            Basic::Brown => "#a52a2a",
            Basic::Tan => "#d2b48c",
            Basic::Violet => "#ee82ee",
            Basic::Beige => "#f5f5dc",
            Basic::Fuchsia => "#ff00ff",
            Basic::Gold => "#ffd700",
            Basic::Magenta => "#ff00ff",
            Basic::Orange => "#ffa500",
            Basic::Pink => "#ffc0cb",
            Basic::Red => "#ff0000",
            Basic::White => "#ffffff",
            Basic::Yellow => "#ffff00",
        }
    }
    #[doc = r" Returns the original color name"]
    pub fn name(&self) -> &'static str {
        match self {
            Basic::Black => "black",
            Basic::Blue => "blue",
            Basic::Cyan => "cyan",
            Basic::Green => "green",
            Basic::Teal => "teal",
            Basic::Turquoise => "turquoise",
            Basic::Indigo => "indigo",
            Basic::Gray => "gray",
            Basic::Purple => "purple",
            Basic::Brown => "brown",
            Basic::Tan => "tan",
            Basic::Violet => "violet",
            Basic::Beige => "beige",
            Basic::Fuchsia => "fuchsia",
            Basic::Gold => "gold",
            Basic::Magenta => "magenta",
            Basic::Orange => "orange",
            Basic::Pink => "pink",
            Basic::Red => "red",
            Basic::White => "white",
            Basic::Yellow => "yellow",
        }
    }
    #[doc = r" Returns the RGB values as a tuple (r, g, b)"]
    pub fn rgb(&self) -> rgb::Rgb<u8> {
        let hex = self.hex().trim_start_matches('#');
        let r = u8::from_str_radix(&hex[0..2], 16).unwrap_or(0);
        let g = u8::from_str_radix(&hex[2..4], 16).unwrap_or(0);
        let b = u8::from_str_radix(&hex[4..6], 16).unwrap_or(0);
        rgb::Rgb { r, g, b }
    }
}
impl From<self::Basic> for String {
    fn from(color: self::Basic) -> Self {
        color.hex().to_string()
    }
}
impl FromHex for Basic {
    type Error = HexParseError;
    fn from_hex<T: AsRef<[u8]>>(hex: T) -> Result<Self, Self::Error> {
        let hex_str =
            std::str::from_utf8(hex.as_ref()).map_err(|_| HexParseError::InvalidCharacter)?;
        let normalized = hex_str.trim_start_matches('#').to_lowercase();
        if normalized.len() != 6 {
            return Err(HexParseError::InvalidLength);
        }
        if !normalized.chars().all(|c| c.is_ascii_hexdigit()) {
            return Err(HexParseError::InvalidCharacter);
        }
        match normalized.as_str() {
            "000000" | "#000000" => Ok(Basic::Black),
            "0000ff" | "#0000ff" => Ok(Basic::Blue),
            "00ffff" | "#00ffff" => Ok(Basic::Cyan),
            "008000" | "#008000" => Ok(Basic::Green),
            "008080" | "#008080" => Ok(Basic::Teal),
            "40e0d0" | "#40e0d0" => Ok(Basic::Turquoise),
            "4b0082" | "#4b0082" => Ok(Basic::Indigo),
            "808080" | "#808080" => Ok(Basic::Gray),
            "800080" | "#800080" => Ok(Basic::Purple),
            "a52a2a" | "#a52a2a" => Ok(Basic::Brown),
            "d2b48c" | "#d2b48c" => Ok(Basic::Tan),
            "ee82ee" | "#ee82ee" => Ok(Basic::Violet),
            "f5f5dc" | "#f5f5dc" => Ok(Basic::Beige),
            "ff00ff" | "#ff00ff" => Ok(Basic::Fuchsia),
            "ffd700" | "#ffd700" => Ok(Basic::Gold),
            "ff00ff" | "#ff00ff" => Ok(Basic::Magenta),
            "ffa500" | "#ffa500" => Ok(Basic::Orange),
            "ffc0cb" | "#ffc0cb" => Ok(Basic::Pink),
            "ff0000" | "#ff0000" => Ok(Basic::Red),
            "ffffff" | "#ffffff" => Ok(Basic::White),
            "ffff00" | "#ffff00" => Ok(Basic::Yellow),
            _ => Err(HexParseError::ColorNotFound),
        }
    }
}
impl std::str::FromStr for Basic {
    type Err = HexParseError;
    fn from_str(s: &str) -> Result<Self, Self::Err> {
        Self::from_hex(s.as_bytes())
    }
}
impl TryFrom<&str> for Basic {
    type Error = HexParseError;
    fn try_from(hex: &str) -> Result<Self, Self::Error> {
        Self::from_hex(hex.as_bytes())
    }
}
impl TryFrom<String> for Basic {
    type Error = HexParseError;
    fn try_from(hex: String) -> Result<Self, Self::Error> {
        Self::from_hex(hex.as_bytes())
    }
}
